import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

export interface TNInputs {
  slideType: string;
  originalTNs: string;
  onSlideInstruction?: string;
  interactivity?: string;
}

export async function fixTeacherNotes(inputs: TNInputs): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
[SLIDE TYPE / DESCRIPTION]: ${inputs.slideType}
[ORIGINAL TNs]: ${inputs.originalTNs}
[OPTIONAL ON-SLIDE INSTRUCTION TEXT]: ${inputs.onSlideInstruction || "Not provided"}
[OPTIONAL INTERACTIVITY NOTES]: ${inputs.interactivity || "Not provided"}

Rewrite the TNs now following ALL rules provided in your system instructions.
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Keep it deterministic
      },
    });

    return response.text?.trim() || "Error: No output generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process the notes. Please try again.");
  }
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-lg font-semibold transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-[#FF9500] hover:bg-[#e68600] text-white shadow-md",
    secondary: "bg-[#00B4D8] hover:bg-[#0096b4] text-white shadow-md",
    outline: "border-2 border-slate-300 hover:bg-slate-50 text-slate-600"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
