};

export default App;

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

export async function fixTeacherNotes(rawNotes: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
[ORIGINAL TEACHER NOTES]: 
${rawNotes}

INSTRUCTION: 
Analyze the notes above to identify the slide type, goal, and interactivity. 
Then, rewrite them following ALL Novakid TN rules (numbered list, T./S. abbreviations, no scripts, click NEXT patterns).
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
      },
    });

    return response.text?.trim() || "Error: No output generated.";
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("entity was not found")) {
      throw new Error("API Key issue. Please re-authenticate if required.");
    }
    throw new Error("Failed to process the notes. Please try again.");
  }
}

