import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

export async function fixTeacherNotes(rawNotes: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Minimal user prompt as the system instruction is now extremely comprehensive
  const prompt = `
[INPUT DATA]:
${rawNotes}

NOW DO THE TASK
Rewrite the TNs according to the rules above.
Return ONLY the corrected TNs.
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
      },
    });

    return response.text?.trim() || "Error: No output generated.";
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("entity was not found")) {
      throw new Error("API Key issue. Please re-authenticate if required.");
    }
    throw new Error("Failed to process the notes. Please try again.");
  }
}

