import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

export interface TNResult {
  fixedNotes: string;
  analysis: string;
}

export async function fixTeacherNotes(rawNotes: string): Promise<TNResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
[INPUT DATA]:
${rawNotes}
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            fixedNotes: {
              type: Type.STRING,
              description: "The clean, standardized, numbered teacher notes.",
            },
            analysis: {
              type: Type.STRING,
              description: "Brief explanation of what was wrong in the original notes.",
            },
          },
          required: ["fixedNotes", "analysis"],
        },
      },
    });

    const json = JSON.parse(response.text || "{}");
    return {
      fixedNotes: json.fixedNotes || "Error: No notes generated.",
      analysis: json.analysis || "No issues identified.",
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("entity was not found")) {
      throw new Error("API Key issue. Please re-authenticate if required.");
    }
    throw new Error("Failed to process the notes. Please try again.");
  }
}

