      doc.text(splitLog, 10, logY + 8);
    }

    doc.save("novakid-teacher-notes.pdf");
  };

  // Helper to render slide headers with styling if they match ### SLIDE X ###
  const renderFixedNotes = (text: string) => {
    return text.split('\n').map((line, i) => {
